pure fn is_even(n: Number) -> Boolean {
    return n % 2 == 0
}

pure fn sum_even_numbers(start: Number, end: Number) -> Number {
    sum = 0
    for i in range(start, end + 1) {
        if is_even(i) {
            sum = sum + i
        }
    }
    return sum
}

