pure fn remove_duplicates(items: [Number]) -> [Number] {
    seen = []
    result = []
    for item in items {
        if not item in seen {
            seen = append(seen, item)
            result = append(result, item)
        }
    }
    return result
}

entry main(input: Text) {
    return to_text(remove_duplicates([1, 3, 2, 3, 1, 4, 2, 5]))
}

pure fn count_chars(text: Text) -> {char: Number} {
    counts = {}
    for char in split(text, "") {
        if char in counts {
            counts[char] = counts[char] + 1
        } else {
            counts[char] = 1
        }
    }
    return counts
}

entry main(x: Text) {
