}

pure fn fibonacci(n: Number) -> [Number] {
    if n <= 0 { return [] }
    if n == 1 { return [0] }
    if n == 2 { return [0, 1] }
    fibs = [0, 1]
    for i in range(2, n) {
        fibs = append(fibs, fibs[i-1] + fibs[i-2])
    }
    return fibs
}

entry main(x: Text) {
    return fibonacci(10)
}

