        ("Hello, how are you?") => ("English")
        ("Ciao, come stai?") => ("Italian")
    }
    on_low_confidence(threshold: 0.5) {
        return "Unknown"
    }
    trace: full
}

entry main(text: Text) {
    return classify_language(text)
}

