import parse_csv from "stdlib/utils"

intent recommend_product(budget: Number) -> Text {
    goal: recommend product with lowest price within budget
}

entry main(input: Text) {
    csv = parse_csv(input)
    products = map(csv, "Product")
    prices = map(csv, "Price")
    prices = map(prices, to_number)
    valid_products = filter(zip(products, prices), (p) => p[1] <= budget)
    if length(valid_products) == 0 {
        return "No products within budget"
    }
    recommended_product = min(valid_products, (p) => p[1])
    return recommended_product[0]
}

