import parse_date from "stdlib/utils"

fn parse_dates(text: Text) -> [Text, Text] {
    parts = split(text, ", ")
    meeting_date = parse_date(parts[0].split(": ")[1])
    deadline_date = parse_date(parts[1].split(": ")[1])
    return [meeting_date, deadline_date]
}

fn days_between(date1: Text, date2: Text) -> Number {
    return abs(to_number(date2) - to_number(date1))
}

intent is_reasonable_timeline(meeting_date: Text, deadline_date: Text) -> Text {
    goal: reasonable_or_not
    constraints {
        days_between(meeting_date, deadline_date) >= 7
    }
}

entry main(text: Text) {
    [meeting_date, deadline_date] = parse_dates(text)
    days = days_between(meeting_date, deadline_date)
    return join(["Days between: ", to_text(days), "\nTimeline is ", is_reasonable_timeline(meeting_date, deadline_date)], "")
}

pure fn count_char_frequencies(text: Text) -> {char: Number} {
