pure fn sort_desc(numbers: [Number]) -> [Number] {
    return sort(numbers, reverse=true)
}

pure fn percentile(value: Number, sorted_list: [Number]) -> Number {
    length = length(sorted_list)
    rank = length - index(sorted_list, value) - 1
    return (rank + 1) / length
}

entry main(numbers: Text) {
    numbers_list = map(split(numbers, ", "), to_number)
    sorted_numbers = sort_desc(numbers_list)
    percentile_42 = percentile(42, sorted_numbers)
    return join([to_text(sorted_numbers), ", percentile of 42: ", to_text(percentile_42)], "")
}

