import stdlib.utils as utils

pure fn mean(numbers: [Number]) -> Number {
    return sum_list(numbers) / length(numbers)
}

pure fn variance(numbers: [Number]) -> Number {
    avg = mean(numbers)
    sum_diff_sq = sum_list(map(numbers, fn(x: Number) -> (x - avg) * (x - avg)))
    return sum_diff_sq / length(numbers)
}

pure fn std_dev(numbers: [Number]) -> Number {
    return sqrt(variance(numbers))
}

intent explain_variance(value: Number) -> Text {
    goal: explain if data is highly variable
}

entry main(numbers: Text) {
    nums = to_number(split(numbers, ", "))
    std_dev_value = std_dev(nums)
    return join(["Standard Deviation: ", to_text(std_dev_value), "\n", explain_variance(std_dev_value)])
}

pure fn reverse_word(word: Text) -> Text {
