fn parse_cities(text: Text) -> [[Text, Number]] {
    items = split(text, ",")
    result = []
    for item in items {
        parts = split(item, ":")
        city = parts[0]
        lat = to_number(parts[1])
        append(result, [city, lat])
    }
    return result
}

fn sort_by_lat(cities: [[Text, Number]]) -> [[Text, Number]] {
    return sort(cities, "by lat")
}

fn describe_pattern(cities: [[Text, Number]]) -> Text {
    if length(cities) == 0 { return "No cities provided" }
    first = cities[0]
    last = cities[length(cities) - 1]
    return join(["Geographic pattern from ", first[0], " (", to_text(first[1]), ") to ", last[0], " (", to_text(last[1]), ")"], "")
}

entry main(input: Text) {
    cities = parse_cities(input)
    sorted_cities = sort_by_lat(cities)
    return describe_pattern(sorted_cities)
}

pure fn fibonacci(n: Number) -> [Number] {
    if n <= 0 { return [] }
    if n == 1 { return [0] }
    if n == 2 { return [0, 1] }
    fibs = [0, 1]
    for i in range(2, n) {
        fibs = append(fibs, fibs[i - 1] + fibs[i - 2])
    }
    return fibs
}

pure fn golden_ratio_appears(fibs: [Number]) -> Boolean {
    if length(fibs) < 2 { return false }
    a = fibs[length(fibs) - 1]
    b = fibs[length(fibs) - 2]
    return abs(a / b - (1 + sqrt(5)) / 2) < 1e-9
}

entry main(n: Text) {
    n = to_number(n)
    fibs = fibonacci(n)
    golden_ratio = golden_ratio_appears(fibs)
    return join([to_text(fibs), " Golden ratio appears: ", to_text(golden_ratio)], "")
}

